#### CELLS TO KEEP
As it is not in vivo / Ex vivo, We do not need to exclude anything



######################## Subseting using subset and metadata #############################################
# Include only Control/Drug
sub_obj <- subset(seurat_object, subset = treatment %in% c("Control", "Drug"))
# Include ALL Except Control/Drug
sub_obj <- subset(seurat_object, subset = !(treatment %in% c("Control", "Drug")))



####### Required library : SeuratWrappers / batchelor)
# "cells_to_keep" have been generated by removing 2 group outliers of 5-10 cells
# We can identify the cell directly by their UMAP coordinates$
# embeddings[,1] = cut vertically  / on X axis
# embeddings[,2] = cut horizontally / on Y axis


cells_to_keep <- names(which(pre_obj_b@reductions$umap@cell.embeddings[,1]<= 5))

  DimPlot( join_obj_1, reduction = 'umap', group.by = 'Phase') + 
    ggplot2::geom_hline(yintercept = 4.2, col= 'blue')
  
  DimPlot( join_obj_1, reduction = 'umap', group.by = 'Phase') + 
    ggplot2::geom_vline(xintercept = 3, col= 'red')

  
qsave(cells_to_keep, "2b_cells_to_keep_RT_in_vivo2.qs")
  
  
  
  
################## Cutting in diagonale :  y=ax+b #######################  

cells_to_keep <- names(which( pre_obj_b@reductions$umap@cell.embeddings[,2] <= 1*pre_obj_b@reductions$umap@cell.embeddings[,2] + 5))


  DimPlot( join_obj_1, reduction = 'umap', group.by = 'Phase') + 
    ggplot2::geom_abline(slope = -1,intercept = 5.6 , col= 'blue')





qsave(cells_to_keep, "2b_cells_to_keep_RT_in_vivo2.qs")







