######### Curation of tiny clusters
#### Creating curated DBscan cluster --> eliminating tiny cluster <100
int_obj1$optics_dbscan10_minptseps_cl0.25_curated <- int_obj1$optics_dbscan10_minptseps_cl0.25
table(int_obj1$optics_dbscan10_minptseps_cl0.25_curated)

# Subseting the tiny clusters
tiny_cluster <- names(which(table(int_obj1$optics_dbscan10_minptseps_cl0.25_curated) <100))
tiny_cluster
# getting the UMI in the 
tiny_cluster_UMI <-  int_obj1@meta.data %>% filter(optics_dbscan10_minptseps_cl0.25_curated %in%  tiny_cluster) %>% rownames()


# Renaming all tiny cluster to NA
int_obj1$optics_dbscan10_minptseps_cl0.25_curated[names(int_obj1$optics_dbscan10_minptseps_cl0.25_curated) %in% tiny_cluster_UMI] <- NA
table(int_obj1$optics_dbscan10_minptseps_cl0.25_curated)

##### Renaming all cluster in a sequenced number
#### using factors
int_obj1$optics_dbscan10_minptseps_cl0.25_curated <- as.factor(int_obj1$optics_dbscan10_minptseps_cl0.25_curated) # because factors will returns all values (whatever its originale value)
levels(int_obj1$optics_dbscan10_minptseps_cl0.25_curated) <- 1:length(levels(int_obj1$optics_dbscan10_minptseps_cl0.25_curated))

levels(int_obj1$optics_dbscan10_minptseps_cl0.25_curated)[levels(int_obj1$optics_dbscan10_minptseps_cl0.25_curated) == "12"] <- NA

table(int_obj1$optics_dbscan10_minptseps_cl0.25_curated)






